const { exec } = require('child_process');
const express = require('express');
const app = express();
app.use(express.json());

app.post('/convert', (req, res) => {
  const { inputFilename, outputFormat } = req.body;

  if (!inputFilename || !outputFormat) {
    return res.status(400).send('Input filename and output format are required');
  }

  const outputFilename = `${inputFilename.split('.').slice(0, -1)}.pdf`;

  const command = `soffice --headless --convert-to ${outputFormat} "${inputFilename}" --outdir .`;

  exec(command, (error, stdout, stderr) => {
    if (error) {
      console.error(`Error: ${error.message}`);
      return res.status(500).send('Conversion failed');
    }
    if (stderr) {
      console.error(`Stderr: ${stderr}`);
      return res.status(500).send('Conversion failed');
    }
    res.download(outputFilename, () => {
      const fs = require('fs');
      fs.unlinkSync(outputFilename);
    });
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});